arguments.new_str:
using Microsoft.ML;
using Microsoft.Extensions.ML;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);

// Train the model at startup and register the pooled prediction engine
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
var allData = mlContext.Data.LoadFromTextFile<ChurnInput>(
    dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" string to boolean Label column
var pipeline = mlContext.Transforms.CustomMapping<ChurnInput, LabelMapping>(
        (input, output) => output.Label = string.Equals(input.ChurnedRaw, "Yes", StringComparison.OrdinalIgnoreCase),
        contractName: "ChurnLabelMapping")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.FastTree(
        labelColumnName: "Label",
        featureColumnName: "Features",
        numberOfLeaves: 4,
        numberOfTrees: 50,
        minimumExampleCountPerLeaf: 1));

var split = mlContext.Data.TrainTestSplit(allData, testFraction: 0.2, seed: 42);
var model = pipeline.Fit(split.TrainSet);

// Evaluate and log metrics
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, " +
    $"F1: {metrics.F1Score:F4}, Accuracy: {metrics.Accuracy:F4}");

// Save model and register PredictionEnginePool
var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
mlContext.Model.Save(model, allData.Schema, modelPath);

builder.Services.AddPredictionEnginePool<ChurnInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "ChurnPredictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (PredictionEnginePool<ChurnInput, ChurnPrediction> pool, ChurnRequest req) =>
{
    var input = new ChurnInput
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory,
    };
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability,
    });
});

app.Run();

// Custom mapping helper for label conversion
public sealed class LabelMapping
{
    public bool Label { get; set; }
}

public sealed record ChurnRequest(float Age, float Income, string Region, float PurchaseHistory);

